enum ActionKind {
    Walking,
    Idle,
    Jumping
}
namespace SpriteKind {
    export const finish = SpriteKind.create()
    export const Button = SpriteKind.create()
    export const Mouse = SpriteKind.create()
    export const sign = SpriteKind.create()
}
controller.up.onEvent(ControllerButtonEvent.Pressed, function () {
    facing = 3
})
function choose_move () {
    boss_move = randint(1, 2)
}
sprites.onOverlap(SpriteKind.Player, SpriteKind.finish, function (sprite, otherSprite) {
    game.gameOver(true)
})
controller.B.onEvent(ControllerButtonEvent.Pressed, function () {
    show = 1
})
function Bossy_boy_start (bool: boolean) {
    boss_start = 1
    pause(2000)
    boss_dude.setFlag(SpriteFlag.Invisible, false)
    tiles.placeOnTile(boss_dude, tiles.getTileLocation(82, 50))
    scene.cameraShake(4, 2000)
    boss_dude.vy = -240
    pause(1000)
    boss_dude.vx = -100
    pause(1000)
    boss_dude.setVelocity(1, 0)
}
controller.left.onEvent(ControllerButtonEvent.Pressed, function () {
    mySprite.setImage(assets.image`Maria idle1`)
    facing = 0
})
sprites.onOverlap(SpriteKind.Enemy, SpriteKind.Projectile, function (sprite, otherSprite) {
	
})
controller.right.onEvent(ControllerButtonEvent.Released, function () {
    frame = 0
})
controller.left.onEvent(ControllerButtonEvent.Released, function () {
    frame = 0
})
controller.right.onEvent(ControllerButtonEvent.Pressed, function () {
    mySprite.setImage(assets.image`Maria idle0`)
    facing = 1
})
controller.up.onEvent(ControllerButtonEvent.Released, function () {
    facing = 0
})
info.onLifeZero(function () {
    game.gameOver(false)
})
controller.B.onEvent(ControllerButtonEvent.Released, function () {
    show = 0
    attack = 1
})
browserEvents.F.onEvent(browserEvents.KeyEvent.Pressed, function () {
    if (facing == 1 && dash_regarge == 1) {
        mySprite.setVelocity(200, 0)
        pause(200)
        mySprite.setVelocity(0, 0)
        dash_regarge = 0
    }
    if (facing == 0 && dash_regarge == 1) {
        mySprite.setVelocity(-200, 0)
        pause(200)
        mySprite.setVelocity(0, 0)
        dash_regarge = 0
    }
})
