sprites.onOverlap(SpriteKind.Player, SpriteKind.Food, function (sprite, otherSprite) {
    mySprite.setVelocity(0, -130)
})
function stop_player (bool: boolean) {
    for (let index = 0; index < 1; index++) {
        mySprite.setVelocity(0, 0)
        pause(2000)
    }
}
function boss_move_1 () {
    if (boss_start == 1) {
        if (boss_dude.vx > 0) {
            boss_dude.setVelocity(0, 0)
            boss_dude.setVelocity(200, -140)
            pause(1500)
            boss_dude.setVelocity(-200, -140)
            pause(1500)
            boss_dude.setVelocity(1, 0)
            boss_move = 0
        }
        if (boss_dude.vx < 0) {
            boss_dude.setVelocity(0, 0)
            boss_dude.setVelocity(-200, -140)
            pause(1500)
            boss_dude.setVelocity(200, -140)
            pause(1500)
            boss_dude.setVelocity(-1, 0)
            boss_move = 0
        }
    }
}
sprites.onOverlap(SpriteKind.Player, SpriteKind.Enemy, function (sprite, otherSprite) {
    info.changeLifeBy(-1)
    pause(1000)
})
